    private Boolean inStock;
    private Float rating;
    private Instant createdAt;
    private Instant updatedAt;

    public Map<String, Object> toMap() {
        Map<String, Object> map = new HashMap<>();
        map.put("id", id);
        map.put("name", name);
        map.put("description", description);
        map.put("brand", brand);
        map.put("category", category);
        map.put("tags", tags);
        map.put("price", price != null ? price.doubleValue() : null);
        map.put("currency", currency);
        map.put("inStock", inStock);
        map.put("rating", rating);
        map.put("createdAt", createdAt != null ? createdAt.toString() : null);
        map.put("updatedAt", updatedAt != null ? updatedAt.toString() : null);
        return map;
    }

    @SuppressWarnings("unchecked")
    public static Product fromMap(Map<String, Object> map) {
        Product product = new Product();
        product.setId((String) map.get("id"));
        product.setName((String) map.get("name"));
        product.setDescription((String) map.get("description"));
        product.setBrand((String) map.get("brand"));
        product.setCategory((String) map.get("category"));
        Object tagsObj = map.get("tags");
        if (tagsObj instanceof List) {
            product.setTags(((List<?>) tagsObj).stream().map(String::valueOf).collect(Collectors.toList()));
        }
        Object priceObj = map.get("price");
        if (priceObj != null) {
            product.setPrice(new BigDecimal(String.valueOf(priceObj)));
        }
        product.setCurrency((String) map.get("currency"));
        Object inStockObj = map.get("inStock");
        if (inStockObj != null) {
            product.setInStock(Boolean.valueOf(String.valueOf(inStockObj)));
        }
        Object ratingObj = map.get("rating");
        if (ratingObj != null) {
            product.setRating(Float.valueOf(String.valueOf(ratingObj)));
        }
        Object createdAtObj = map.get("createdAt");
        if (createdAtObj != null) {
            product.setCreatedAt(Instant.parse(String.valueOf(createdAtObj)));
        }
        Object updatedAtObj = map.get("updatedAt");
        if (updatedAtObj != null) {
            product.setUpdatedAt(Instant.parse(String.valueOf(updatedAtObj)));
        }
        return product;
    }

